SELECT COUNT(*)
FROM xeus.crms_cctv_stat


        AND mgr_seq = #{mgrSeq}::numeric



        AND cctv_mgr_no = #{cctvMgrNo}



        AND reqst_dat = #{startDat}



        AND reqst_dat = #{endDat}



        AND stat_data = #{statData}



        AND valid_yn = #{validYn}

SELECT mgr_seq, cctv_mgr_no, start_dat, end_dat, stat_data, valid_yn

FROM xeus.crms_cctv_stat AS stat



        AND stat.mgr_seq = #{mgrSeq}::numeric



        AND stat.cctv_mgr_no = #{cctvMgrNo}



        AND stat.reqst_dat = #{startDat}



        AND stat.reqst_dat = #{endDat}



        AND stat.stat_data = #{statData}



        AND stat.valid_yn = #{validYn}





        ${sortCol} ${sortTyp}


        stat.mgr_seq ASC




    LIMIT ${limit} OFFSET ${offset}

mapper.update:
UPDATE xeus.crms_cctv_stat
SET
    cctv_mgr_no = #{cctvMgrNo}
    , start_dat = #{startDat}
    , end_dat = #{endDat}
    , stat_data = #{statData}
    , valid_yn = #{validYn}
WHERE mgr_seq = #{mgrSeq}::numeric
